const OPENAI_API_KEY = $env['OPENAI_API_KEY'];
const product = $input.first().json.product;
const topic = $input.first().json.topic;
const target_audience = $input.first().json.target_audience;
const script_style = $input.first().json.script_style || 'ab_test';

// ── VARIANT A: Pixar Story ──────────────────────────────────────────
const PIXAR_SYSTEM = `You are the creative director for @vitalessencehealth, a TikTok Shop brand with a wacky, fun, Pixar-style animated aesthetic. Your scripts are playful, emotionally resonant storytelling — like an animated short film where the product saves the day.

BRAND VOICE:
- Energetic, fun, and warm. Like a cartoon character who found the secret to feeling amazing.
- Wacky but relatable. Exaggerated reactions and situations are encouraged.
- Storytelling-first: the audience struggle is the hero. The product is the magical solution.
- Never salesy. The CTA lands naturally as the happy ending.

PRODUCT CONTEXT:
- vitamins: Daily supplement stack. Energy, mental clarity, filling nutritional gaps. Key emotion: I finally feel like the main character of my own life.
- gut_health: Digestive enzyme and probiotic blend. Bloating relief, gut-brain connection, food freedom. Key emotion: I can finally eat my favorite foods without my stomach staging a revolt.
- nobs_toothpaste: Toothpaste tablets — zero plastic, clean ingredients, travel-friendly. Whiter teeth, fresh breath, clean beauty. Key emotion: My bathroom routine just became the main character arc.
- magnesium_complex: 8-form magnesium complex. Energy, sleep, muscle recovery, stress relief, leg cramps, bloating, mood. Key emotion: My body finally has everything it was missing all along.

SCRIPT STRUCTURE — always follow this arc:
[HOOK 0-3s]: Wacky, surprising, stops the scroll. Exaggerated situation or bold question.
[PROBLEM 3-10s]: Relatable struggle told with humor and heart.
[DISCOVERY 10-20s]: Finding @vitalessencehealth. Feels like fate, not an ad.
[TRANSFORMATION 20-35s]: The animated glow-up. Specific, sensory, fun.
[CTA 35-45s]: Soft close pointing to TikTok Shop. One clear joyful action.

SCENE STRUCTURE:
Return exactly 20 scene descriptions. Scenes 1-17 are animated story moments (AI-generated Pixar style). Scenes 18-20 are CTA moments — describe them as IRL product shots the creator will film themselves (TikTok Shop overlay, product closeup, creator holding product).

OUTPUT FORMAT strict JSON no markdown:
{"voiceover": "<clean voiceover 75-115 words>", "scenes": ["<scene 1 description>", ..., "<scene 20 description>"], "hook": "<scroll-stopping first line>", "cta": "<final CTA line>"}`;

// ── VARIANT B: Symptom Stack ────────────────────────────────────────
const SYMPTOM_STACK_SYSTEM = `You are the performance copy director for @vitalessencehealth, a TikTok Shop supplement brand. Your scripts use the proven "Symptom Stack" formula — the most viral format in health supplement TikTok.

FORMULA — follow in exact order:
1. SYMPTOM LIST (0-10s): 5-7 specific symptoms each mapped to a named form of the product. Use visceral, body-specific language. Make the viewer self-diagnose from the list.
2. PIVOT (10-14s): "But buying all this separately is expensive and nobody wants to take X pills a day."
3. SOLUTION (14-20s): One capsule/complex that has everything. Name the number of forms. Sugar-free, gluten-free.
4. BENEFITS TRIO (20-28s): Always exactly 3: sleep deeper / wake up energized / think clearer.
5. AUTHORITY STAT (28-33s): "Magnesium supports 400+ functions in your body. More than half of Americans are deficient."
6. CTA + URGENCY (33-45s): Price anchor ($13-15) + TikTok Shop + "orange cart" + "tap before it disappears."

HOOK TYPES — pick the most unexpected:
- Visceral body symptom (specific, body-level, slightly shocking but relatable)
- Visual body exaggeration (funny but real — "belly like you're 3 months pregnant")
- Performance or energy fear
- Bedroom or relationship angle

MAGNESIUM SYMPTOM MAP — use these exact pairings:
- Private parts odor / BV → orotate
- Bloating after eating → carbonate
- Low libido / no desire in the bedroom → malate
- Leg cramps at night → glycinate
- Headaches that won't go away → taurate
- Low energy / tired all day → citrate
- Can't sleep / insomnia → threonate
- Stress and anxiety → taurate
- Brain fog / mental cloudiness → aspartate
- Muscle soreness or weakness → malate
- Waking up to pee at night → glycinate
- Eye twitching → taurate
- Heart palpitations → orotate

PRODUCT CONTEXT:
- magnesium_complex: 8-form magnesium complex. Sugar-free. Gluten-free. One capsule per day. $13-15 on TikTok Shop.
- vitamins: Multi-nutrient daily stack. One capsule. Energy, clarity, immunity.
- gut_health: Digestive enzyme + probiotic blend. One capsule. Bloating, gut-brain connection.
- nobs_toothpaste: Toothpaste tablets. One tablet per brush. Whiter teeth, fresh breath, zero plastic.

SCENE STRUCTURE:
Return exactly 20 scene descriptions. Scenes 1-17 are visual moments for each symptom/solution pair and the transformation (realistic lifestyle photography OR bold text-on-screen graphic style). Scenes 18-20 are IRL CTA product shots.

OUTPUT FORMAT strict JSON no markdown:
{"voiceover": "<45s script 85-120 words>", "scenes": ["<scene 1>", ..., "<scene 20>"], "hook": "<first visceral symptom line>", "cta": "<orange cart urgency line>"}`;

// ── Pixar Scorer ─────────────────────────────────────────────────────
const PIXAR_SCORER = `You are a TikTok quality judge for @vitalessencehealth Pixar Story scripts. Score on 5 criteria 1-5 each. Pass threshold is 18 out of 25.

1. HOOK STRENGTH (1-5) — stops scroll in 3 seconds, wacky and surprising
2. EMOTIONAL ARC (1-5) — clear fun problem-to-magical-solution journey
3. BRAND VOICE (1-5) — wacky Pixar energy, warm, not salesy
4. PRODUCT ACCURACY (1-5) — correct specific benefits, no compliance red flags
5. CTA EFFECTIVENESS (1-5) — natural happy ending pointing to TikTok Shop

OUTPUT strict JSON: {"total_score": <5-25>, "pass": <true if >=18>, "feedback": "<2-3 sentences>", "criteria_scores": {"hook_strength": <1-5>, "emotional_arc": <1-5>, "brand_voice": <1-5>, "product_accuracy": <1-5>, "cta_effectiveness": <1-5>}}`;

// ── Symptom Stack Scorer ─────────────────────────────────────────────
const SYMPTOM_SCORER = `You are a TikTok quality judge for @vitalessencehealth Symptom Stack scripts. Score on 5 criteria 1-5 each. Pass threshold is 18 out of 25.

1. HOOK VISCERAL IMPACT (1-5) — first symptom is body-specific and makes the viewer self-diagnose immediately
2. SYMPTOM SPECIFICITY (1-5) — each symptom maps to a named form, feels medically credible and researched
3. PIVOT CLARITY (1-5) — the "buying separately is expensive" line lands clean and natural, not forced
4. BENEFITS TRIO + AUTHORITY (1-5) — exactly 3 benefits stated cleanly plus the deficiency stat
5. CTA URGENCY (1-5) — price anchor present, orange cart mentioned, scarcity feels real

OUTPUT strict JSON: {"total_score": <5-25>, "pass": <true if >=18>, "feedback": "<2-3 sentences>", "criteria_scores": {"hook_visceral_impact": <1-5>, "symptom_specificity": <1-5>, "pivot_clarity": <1-5>, "benefits_authority": <1-5>, "cta_urgency": <1-5>}}`;

async function callOpenAI(messages, temperature, maxTokens) {
  const res = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${OPENAI_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: 'gpt-4o', messages, temperature, max_tokens: maxTokens, response_format: { type: 'json_object' } })
  });
  const data = await res.json();
  if (!res.ok) throw new Error('OpenAI error: ' + JSON.stringify(data.error || data));
  return JSON.parse(data.choices[0].message.content);
}

async function generateVariant(systemPrompt, scorerPrompt, variantLabel) {
  let attempt = 0, script = null, score = null, passed = false;
  while (attempt < 3) {
    attempt++;
    script = await callOpenAI([
      { role: 'system', content: systemPrompt },
      { role: 'user', content: `Write a TikTok script for @vitalessencehealth.\n\nProduct: ${product}\nTopic: ${topic}\nTarget Audience: ${target_audience}\n\nReturn strict JSON with exactly 20 scenes.` }
    ], 0.85, 1200);
    if (!Array.isArray(script.scenes) || script.scenes.length < 18) {
      script.scenes = (script.scenes || []).concat(Array(20).fill('Scene')).slice(0, 20);
    }
    score = await callOpenAI([
      { role: 'system', content: scorerPrompt },
      { role: 'user', content: `Score this script.\n\nProduct: ${product}\nAudience: ${target_audience}\n\nScript: ${JSON.stringify(script)}\n\nReturn strict JSON.` }
    ], 0.2, 600);
    if (score.pass === true) { passed = true; break; }
  }
  return { variant: variantLabel, script, score, passed, attempt_count: attempt, product, topic, target_audience };
}

let results = [];
if (script_style === 'pixar_story') {
  results = [await generateVariant(PIXAR_SYSTEM, PIXAR_SCORER, 'A')];
} else if (script_style === 'symptom_stack') {
  results = [await generateVariant(SYMPTOM_STACK_SYSTEM, SYMPTOM_SCORER, 'B')];
} else {
  // ab_test: generate both in parallel
  const [varA, varB] = await Promise.all([
    generateVariant(PIXAR_SYSTEM, PIXAR_SCORER, 'A'),
    generateVariant(SYMPTOM_STACK_SYSTEM, SYMPTOM_SCORER, 'B')
  ]);
  results = [varA, varB];
}

return results.map(v => ({ json: v }));

const FAL_API_KEY = $env['FAL_API_KEY'];

const scriptData = $('IF - Score Gate').item.json;
const script = scriptData.script;
const score = scriptData.score;
const product = scriptData.product;
const topic = scriptData.topic;
const target_audience = scriptData.target_audience;
const attempt_count = scriptData.attempt_count;
const variant = scriptData.variant;
const folderId = $('Google Drive - Create Content Folder').item.json.id;

const audioData = $('ElevenLabs - Adam Voiceover').item.binary?.voiceover_audio?.data || '';

// Image style per variant
const PIXAR_STYLE = '3D animated Pixar style, vibrant saturated colors, wacky exaggerated cartoon characters, playful fun energy, bright cheerful lighting, Pixar movie render quality, clean animation aesthetic, no text overlays, no watermarks, no logos';
const SYMPTOM_STYLE = 'realistic lifestyle photography, clean bright minimal aesthetic, health and wellness brand, natural warm lighting, authentic human moments, magazine-quality composition, no text overlays, no watermarks, no logos';

const imageStyle = variant === 'A' ? PIXAR_STYLE : SYMPTOM_STYLE;

const productContext = {
  vitamins: variant === 'A'
    ? 'cartoon health supplement capsules, colorful animated wellness energy, glowing vitamin bottle'
    : 'real supplement bottle on marble counter, morning light, healthy woman',
  gut_health: variant === 'A'
    ? 'animated gut health, happy cartoon stomach character, probiotic capsule hero'
    : 'real probiotic bottle, woman eating freely at restaurant, comfortable and happy',
  nobs_toothpaste: variant === 'A'
    ? 'cartoon toothpaste tablet, animated bright smile, eco bathroom character'
    : 'real toothpaste tablets on clean bathroom counter, bright white smile closeup',
  magnesium_complex: variant === 'A'
    ? 'cartoon magnesium capsules, animated glowing body with energy sparks, wacky wellness character'
    : 'real magnesium complex bottle, bedside table, woman sleeping peacefully or waking up energized'
}[product] || (variant === 'A' ? 'animated health wellness supplement' : 'real health supplement product');

async function generateFluxImage(sceneDescription) {
  const prompt = `${sceneDescription}, ${productContext} | ${imageStyle}`;
  const res = await fetch('https://fal.run/fal-ai/flux/schnell', {
    method: 'POST',
    headers: { 'Authorization': `Key ${FAL_API_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      prompt,
      image_size: 'portrait_16_9',
      num_inference_steps: 4,
      num_images: 1,
      enable_safety_checker: false
    })
  });
  const data = await res.json();
  if (!res.ok) throw new Error('Flux Schnell error: ' + JSON.stringify(data));
  const imgRes = await fetch(data.images[0].url);
  const buffer = await imgRes.arrayBuffer();
  return Buffer.from(buffer).toString('base64');
}

const scenes = script.scenes.slice(0, 20);
const imageB64Array = await Promise.all(scenes.map(generateFluxImage));

const images = scenes.map((scene, i) => ({
  index: i + 1,
  filename: `${variant}_scene_${String(i + 1).padStart(2, '0')}.jpg`,
  b64: imageB64Array[i],
  description: scene,
  is_irl: i >= 17,
  folderId
}));

const styleLabel = variant === 'A' ? 'Pixar Story' : 'Symptom Stack';
const imageStyleLabel = variant === 'A' ? 'Wacky Pixar 3D Animated (Flux Schnell)' : 'Realistic Lifestyle Photography (Flux Schnell)';
const line = String.fromCharCode(9472).repeat(48);

const sceneList = scenes.map((s, i) => {
  const tag = i >= 17 ? ' [IRL — film this yourself]' : ` [AI ${variant === 'A' ? 'Pixar' : 'Lifestyle'} image generated]`;
  return `[SCENE ${String(i+1).padStart(2,'0')}]${tag}:\n${s}`;
}).join('\n\n');

const criteriaLines = Object.entries(score.criteria_scores)
  .map(([k, v]) => `  ${k.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()).padEnd(26)}: ${v}/5`)
  .join('\n');

const scriptText = `VITALESSENCE TIKTOK CONTENT PACKAGE — VARIANT ${variant} (${styleLabel})\n${'='.repeat(54)}\n\nProduct: ${product}\nTopic: ${topic}\nTarget Audience: ${target_audience}\nGenerated: ${new Date().toISOString()}\nScript Style: ${styleLabel}\nImage Style: ${imageStyleLabel}\n\n${line}\nSCORE REPORT\n${line}\nTotal: ${score.total_score}/25 — ${score.pass ? 'PASSED ✓' : 'FAILED ✗'}  |  Attempts: ${attempt_count}\n${criteriaLines}\nFeedback: ${score.feedback}\n\n${line}\nSCRIPT\n${line}\nHOOK: ${script.hook}\n\nVOICEOVER:\n${script.voiceover}\n\nCTA: ${script.cta}\n\n${line}\n20 SCENE DESCRIPTIONS\n${line}\nScenes 01-17: AI-generated ${variant === 'A' ? 'Pixar-style' : 'lifestyle'} images (in this Drive folder)\nScenes 18-20: IRL footage — film yourself with the product for these\n\n${sceneList}\n\n${line}\nEDITING NOTES\n${line}\n1. Import ${variant}_scene_01 through ${variant}_scene_17 as slides in CapCut\n2. Layer ${variant}_voiceover.mp3 over the full timeline\n3. Replace scenes 18-20 with your IRL product footage\n4. Add TikTok Shop product link sticker on the CTA frame\n5. Export 1080x1920 for TikTok\n6. POST AS VARIANT ${variant} — track views, saves, and purchases separately for A/B data\n`;

return [{
  json: { script, score, product, topic, target_audience, attempt_count, variant, styleLabel, folderId, scriptText, images, total_images: images.length },
  binary: {
    voiceover_audio: { data: audioData, mimeType: 'audio/mpeg', fileName: `${variant}_voiceover.mp3` }
  }
}];

const item = $input.first().json;
return [{
  json: { filename: item.filename, index: item.index, folderId: item.folderId },
  binary: {
    image: { data: item.b64, mimeType: 'image/jpeg', fileName: item.filename }
  }
}];

